async (params, browser) => {
  // Open page
  await browser.open(`https://www.strava.com/athletes/${params.athlete_id}`)

  // Wait for content
  await browser.waitForSelector('h1, [class*="Athlete"], .athlete-profile', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const name = document.querySelector('h1, [class*="AthleteName"]')?.textContent?.trim()||''; const loc = document.querySelector('[class*="location"], .athlete-location')?.textContent?.trim()||''; const stats = {}; document.querySelectorAll('[class*="Stat"], .inline-stats .stat, .athlete-stats span').forEach(el => { const lbl = el.querySelector('[class*="Label"], .stat-subtext')?.textContent?.trim()?.toLowerCase()||''; const val = el.querySelector('[class*="Value"], .stat-text')?.textContent?.trim()||''; if(lbl&&val) stats[lbl]=val; }); const activities = Array.from(document.querySelectorAll('[class*="Activity"], .feed-entry')).slice(0,10).map(el => ({ title: el.querySelector('a, h3')?.textContent?.trim()||'', date: el.querySelector('time, .timestamp')?.textContent?.trim()||'' })); return { athlete_id: '' + params.athlete_id + '', name, location: loc, stats, recent_activities: activities, url: window.location.href }`)

  return page_data
}
